class Solution {
    public int maxScore(String s) {
        int max = 0;
        int ones = 0;
        for (int i = 0; i < s.length() - 1; i++) {
            if (s.charAt(i) == '1') ones++;
            int zeros = s.length() - i - 1;
            int score = ones + zeros - ones;
            max = Math.max(max, score);
        }
        return max;
    }
}
